create table dirkspzm32.meldung_daten (
    sid                  varchar2(2 char) not null enable,
    firma_nr             number(6, 0) not null enable,
    engine_id            number(*, 0),
    md_id                number(10, 0) not null enable,
    md_gruppe            number(3, 0) not null enable,
    md_index             number(9, 2) not null enable,
    md_bereich           varchar2(30 char) not null enable,
    md_status            varchar2(4 char) not null enable,
    md_kommt             date not null enable,
    md_geht              date,
    md_hilfstext         varchar2(15 char),
    md_ausloes_md_id     number(10, 0),
    md_param_1           varchar2(50 char),
    md_param_2           varchar2(50 char),
    md_typ               varchar2(6 char),
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0),
    md_info_text         varchar2(250 char),
    md_initial_index     number(9, 2),
    md_detail_index      number(*, 0)
);

alter table dirkspzm32.meldung_daten
    add constraint check_md_status
        check ( md_status in ( 'K', 'KG', 'KGQ' ) ) enable;

alter table dirkspzm32.meldung_daten
    add constraint pk_meldung_daten primary key ( md_id )
        using index enable;


